class ParkingFinderScreen extends StatefulWidget {
  @override
  _ParkingFinderScreenState createState() => _ParkingFinderScreenState();
}

class _ParkingFinderScreenState extends State<ParkingFinderScreen> {
  final Location _location = Location();
  List<ParkingSpot> _parkingSpots = [];

  @override
  void initState() {
    super.initState();
    _fetchParkingSpots();
  }

  void _fetchParkingSpots() async {
    try {
      // Check if location is enabled
      if (_location.isEnabled) {
        final location = await _location.getCurrentLocation();
        final response = await http.get(Uri.parse('https://api.parkingfinder.com/search?lat=${location.latitude}&lon=${location.longitude}'));
        if (response.statusCode == 200) {
          final List<dynamic> data = json.decode(response.body);
          _parkingSpots = data.map((item) => ParkingSpot.fromJson(item)).toList();
        }
      }
    } catch (e) {
      print('Error fetching parking spots: $e');
    }
    setState(() {});
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text('Parking Finder'),
      ),
      body: _parkingSpots.isEmpty
          ? Center(child: Text('No parking spots found.'))
          : ListView.builder(
              itemCount: _parkingSpots.length,
              itemBuilder: (context, index) {
                return ParkingSpotCard(
                  spot: _parkingSpots[index],
                );
              },
            ),
    );
  }
}
