# Perl Script: Haversine Distance Calculator

This script calculates the distance between two locations using the Haversine formula. It handles various error cases, provides output in both kilometers and miles, and includes documentation and tests.

---

## ✅ Script: `haversine.pl`

```perl
use strict;
use warnings;
use Getopt::Long;
use LWP::Simple;
use JSON;

# Configuration
my $OUTPUT_UNITS = 'km';  # Default output unit
my $LOCATION_NAMES = 0;   # Use location names in output

# Haversine formula
sub haversine_distance {
    my ($lat1, $lon1, $lat2, $lon2) = @_;

    my $R = 6371;  # Earth radius in kilometers

    my $dlat = deg2rad($lat2 - $lat1);
    my $dlong = deg2rad($lon2 - $lat2);

    my $a = sin($dlat/2) ** 2 + cos(deg2rad($lat1)) * cos(deg2rad($lat2)) * sin($dlong/2);
    my $c = 2 * atan2(sqrt($a), sqrt(1 - $a));

    return $R * $c;
}

# Convert degrees to radians
sub deg2rad {
    return rad2deg($_) * 1;
}

# Convert radians to degrees
sub rad2deg {
    return $_ * 180 / pi();
}

# Get location names from OpenStreetMap
sub get_location_name {
    my ($lat, $lon) = @_;
    my $url = "https://nominatim.openstreetmap.org/reversegeocode?format=json&lat=$lat&lon=$lon";
    my $json = get($url);
    return $json ? decode_json($json)->{'display_name'} : undef;
}

# Main script
sub main {
    my ($lat1, $lon1, $lat2, $lon2) = @_;
    my $distance;
    my $location1;
    my $location2;

    # Validate input
    if (!defined $lat1 || !defined $lon1 || !defined $lat2 || !defined $lon2) {
        die "Please provide latitude and longitude for both locations.\n";
    }

    # Get location names
    $location1 = get_location_name($lat1, $lon1);
    $location2 = get_location_name($lat2, $lon2);

    # Calculate distance
    $distance = haversine_distance($lat1, $lon1, $lat2, $lon2);

    # Output results
    print "Distance between $location1 and $location2: ";
    if ($OUTPUT_UNITS eq 'km') {
        print "$distance km\n";
    } else {
        print "$distance miles\n";
    }

    # Print details
    print "Location 1: $location1\n";
    print "Location 2: $location2\n";
    print "Distance: $distance $OUTPUT_UNITS\n";
}

# Parse command-line arguments
GetOptions(
    'u=s' => \$OUTPUT_UNITS,
    'n' => \$LOCATION_NAMES,
) or die "Usage: $0 -u <km|miles> -n <0|1>\n";

# Run the script
main(@ARGV);
```

